class Solution:
    def combinationSum(self, candidates: list[int], target: int) -> list[list[int]]:
        result = []
        candidates.sort() # Sorting helps with pruning and can be useful in similar problems

        def backtrack(current_combination, remaining_target, start_index):
            if remaining_target == 0:
                result.append(list(current_combination))
                return
            if remaining_target < 0:
                return

            for i in range(start_index, len(candidates)):
                candidate = candidates[i]
                # Optimization: if current candidate is already greater than the remaining target,
                # then all subsequent candidates will also be greater (since sorted),
                # so we can stop exploring this path.
                if candidate > remaining_target:
                    break

                current_combination.append(candidate)
                # Recursive call: pass `i` (not `i + 1`) to allow reusing the same number.
                backtrack(current_combination, remaining_target - candidate, i)
                current_combination.pop() # Backtrack: remove the last added number

        backtrack([], target, 0)
        return result
